class Solution:
    def minOrAfterOperations(self, nums: List[int], k: int) -> int:
        n = len(nums)
        res = 0
        for i in range(30, -1, -1):
            mask = (1 << i)
            cnt = 0
            curr = 0
            for num in nums:
                curr &= num
                if (curr & mask) == 0:
                    cnt += 1
                    curr = 0
            if cnt > k:
                res |= mask
        return res
